import React, { useState } from "react";
import { Box, Button, Container, TextField, Typography, Alert, CircularProgress } from "@mui/material";
import { useNavigate } from "react-router-dom";
import axios from "axios";

export default function Login() {
  const navigate = useNavigate();
  const [mobile, setMobile] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const validateMobile = (m) => /^[6-9]\d{9}$/.test(m);

  const handleSubmit = async (e) => {
    e?.preventDefault();
    if (!validateMobile(mobile)) {
      setError("Mobile must start with 6-9 and be 10 digits.");
      return;
    }
    setError("");
    setLoading(true);
    try {
      const res = await axios.post("http://localhost:5000/api/auth/login", { mobile }, { timeout: 10000 });
      if (res.data?.success) {
        // login success
        navigate("/dashboard");
      } else {
        setError(res.data?.message || "Login failed");
      }
    } catch (err) {
      console.error("Login request error:", err);
      setError(err.response?.data?.message || "Server error. Check backend.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Box component="form" onSubmit={handleSubmit} sx={{ mt: 8, p: 4, boxShadow: 3, borderRadius: 2 }}>
        <Typography variant="h4" align="center" sx={{ color: "orangered", fontWeight: "bold" }}>Rider App</Typography>
        <Typography align="center" sx={{ mb: 2 }}>Welcome back — login with your mobile</Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

        <TextField
          fullWidth
          label="Mobile Number"
          value={mobile}
          onChange={(e) => setMobile(e.target.value)}
          margin="normal"
          inputProps={{ maxLength: 10 }}
          required
        />

        <Button type="submit" fullWidth variant="contained" sx={{ mt: 2, bgcolor: "orangered", "&:hover": { bgcolor: "darkred" } }} disabled={loading}>
          {loading ? <CircularProgress size={22} sx={{ color: "white" }} /> : "Login"}
        </Button>
      </Box>
    </Container>
  );
}
